// // When VPWR is high and VGND is low, tap_output should be HIGH; otherwise, it should be LOW.
module top_module(
    input VPWR,
    input VGND,
    output reg tap_output
);always @(*) begin
    if (VPWR && !VGND) begin
        tap_output = 0;
    end else if (!VPWR && VGND) begin
        tap_output = 1;
    end
end

endmodule
